import type { FilterConfig } from "./types";
import { ResizeHandle } from "./ResizeHandle";
import { useResize } from "./hooks/useResize";

export interface BrowsePanelProps {
  isOpen: boolean;
  filterConfig: FilterConfig;
  onTogglePanel: () => void;
  onFilterChange: (key: keyof FilterConfig, value: any) => void;
  onWidthChange: (width: number) => void;
  initialWidth: number;
}

export function BrowsePanel(props: BrowsePanelProps) {
  const resize = useResize({
    initialWidth: props.initialWidth,
    minWidth: 250,
    maxWidth: 600,
    closeThreshold: 100,
    onWidthChange: props.onWidthChange,
    onClose: props.onTogglePanel,
  });

  return (
    <div
      class={`browse-panel ${!props.isOpen ? "collapsed" : ""} ${
        resize.isDragging() ? "resizing" : ""
      }`}
      style={`
        flex-basis: ${props.isOpen ? resize.width() + "px" : "0"};
        flex-shrink: 0;
        background: #2a2a2a;
        border-right: 1px solid #3a3a3a;
        padding: ${props.isOpen ? "20px" : "0"};
        overflow: hidden;
        transition: flex-basis 0.3s ease, padding 0.3s ease;
        position: relative;
      `}
    >
      {/* Sticky Header Bar */}
      <div
        style={`
          position: sticky;
          top: 0;
          background: #2a2a2a;
          border-bottom: 1px solid #3a3a3a;
          padding: 8px 16px;
          margin: -20px -20px 20px -20px;
          display: flex;
          justify-content: space-between;
          align-items: center;
          z-index: 10;
        `}
      >
        <h3 style="margin: 0; font-size: 14px; color: #e0e0e0; font-weight: 600;">
          Browse
        </h3>
        <button
          onClick={props.onTogglePanel}
          title="Close panel"
          style={`
            background: transparent;
            border: none;
            color: #888;
            cursor: pointer;
            font-size: 16px;
            padding: 4px;
            border-radius: 4px;
            transition: all 0.2s;
            line-height: 1;
          `}
        >
          ×
        </button>
      </div>

      {props.isOpen && (
        <div
          class="filter-section"
          style="margin-bottom: 24px; overflow-y: auto;"
        >
          <h3 style="margin: 0 0 12px 0; font-size: 16px; color: #e0e0e0;">
            🔍 Name Search
          </h3>
          <input
            class="filter-input"
            type="text"
            placeholder="Search by filename..."
            value={props.filterConfig.name}
            onInput={(e) => props.onFilterChange("name", e.currentTarget.value)}
            style={`
              width: 100%;
              padding: 8px;
              background: #1a1a1a;
              border: 1px solid #3a3a3a;
              border-radius: 4px;
              color: #e0e0e0;
              font-size: 14px;
            `}
          />
        </div>
      )}

      <ResizeHandle
        position="right"
        isDragging={resize.isDragging()}
        onMouseDown={(e) => resize.handleMouseDown(e, "left")}
      />

      <style>{`
        .filter-input:focus {
          outline: none;
          border-color: #0070f3;
        }

        .browse-panel button[title="Close panel"]:hover {
          background: rgba(255, 255, 255, 0.1) !important;
          color: #ff4444 !important;
        }
      `}</style>
    </div>
  );
}

export default BrowsePanel;
